std::vector<double> applyDiscount(const std::vector<double>& prices, double discountRate) {
    std::vector<double> discountedPrices;
    discountedPrices.reserve(prices.size());

    for (const double& price : prices) {
        double discounted = price * (1.0 - discountRate);
        discounted = std::round(discounted * 100) / 100;
        discountedPrices.push_back(discounted);
